//Ambil data mentah dari HTTP Request node
const response = $input.first().json;

//Masuk ke dalam struktur, sampai ke array components
const components = response.data.pdpMainInfo.components;

//Cari kotak yang labelnya "product_content"
const productContentBox = components.find(item => item.name === "product_content");

//Ambil isi kotak itu (data[0], karena isinya array 1 elemen)
const productData = productContentBox.data[0];



return [
  {
    json: {
      nama_produk: productData.name,
      harga: productData.price.value,
      harga_format: productData.price.priceFmt,
      stok: productData.stock.value,
      dicek_pada: new Date().toISOString()
    }
  }
];

//Ambil harga BARU dari hasil scraping (Code node paling awal)
const hargaBaru = $('Code in JavaScript').item.json.harga;
const namaProduk = $('Code in JavaScript').item.json.nama_produk;
const hargaBaruFormat = $("Code in JavaScript").item.json.harga_format;
const stokBaru = $('Code in JavaScript').item.json.stok;

//Ambil harga LAMA dari Google Sheets (input node ini sendiri)
const dataSheet = $("Loop Over Items").item.json;
const hargaLama = dataSheet.harga_terakhir;


// Cek dulu: kalau stok habis, data harga dari API tidak bisa dipercaya
const belumAdaHistori = !hargaLama;
const stokHabis = stokBaru === 0;

let hargaBaruFinal, hargaBaruFormatFinal, berubah, selisih, arah, hargaLamaFormat;

if (belumAdaHistori) {
  // Jangan timpa baseline, anggap tidak ada perubahan
  hargaBaruFinal = hargaBaru;
  hargaBaruFormatFinal = hargaBaruFormat;
  hargaLamaFormat = "0";
  berubah = false;
  selisih = 0;
  arah = "baseline_baru";
} else if (stokHabis) {
  // stok habis jgn timpa baseline
  hargaBaruFinal = hargaLama;
  hargaBaruFormatFinal = "Rp" + hargaLama.toLocaleString("id-ID");
  hargaLamaFormat = hargaBaruFormatFinal;
  berubah = false;
  selisih = 0;
  arah = "tetap";
} else {
  hargaLamaFormat = "Rp" + hargaLama.toLocaleString("id-ID");
  hargaBaruFinal = hargaBaru;
  hargaBaruFormatFinal = hargaBaruFormat;
  berubah = hargaBaru !== hargaLama;
  selisih = Math.abs(hargaBaru - hargaLama);
  arah = (hargaBaru - hargaLama) > 0 ? "naik" : "turun";
}

return [
  {
    json: {
      nama_produk: namaProduk,
      harga_lama: hargaLama,
      harga_baru: hargaBaruFinal,
      harga_baru_format: hargaBaruFormatFinal,
      berubah: berubah,
      selisih: selisih,
      arah: arah,
      harga_lama_format: hargaLamaFormat,
      row_number: dataSheet.row_number,
      stokHabis: stokHabis,
      belum_ada_histori: belumAdaHistori
    }
  }
]

