const item = $input.first().json;
const url = item.url_produk;

const afterDomain = url.split('tokopedia.com/')[1];
const pathOnly = afterDomain.split('?')[0]; 
const pathParts = pathOnly.split('/').filter(part => part !== '');

const shopDomain = pathParts[0];
const productKey = pathParts[1];

return [
  {
    json: {
      ...item,
      product_key: productKey,
      shop_domain:  shopDomain,
    }
  }
]
